def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for idx, cap in enumerate(bins):
        if cap <= 0:
            priorities[idx] = np.inf
            continue
        usage = item / cap
        base_priority = 60.0 + np.log1p(cap**2) * 30
        fluctuation = 0.0
        if usage > 5:
            base_priority += 7000 * np.power(usage, 1.3)
            if cap > 15:
                base_priority += 150 * np.cbrt(cap) + 50 * np.cos(cap * 2)
            else:
                base_priority -= 50 * usage ** 1.2
            for i in range(1, 7):
                fluctuation += ((-1) ** i) * np.sin(usage * np.pi * i * 0.75) * 25 / i
                if i % 2 == 0 and cap % 2 < 1:
                    fluctuation += np.log1p(cap) * i
        elif 4 < usage <= 5:
            delta = usage - 4
            base_priority += 2000 * delta ** 2 + 300 * (1 - delta ** 0.6)
            for j in range(1, 10):
                fluctuation += np.cos(usage * np.pi * (j ** 1.5)) * 30 / j
                if j % 3 == 0:
                    fluctuation -= np.sin(cap * j) * 10
            if int(cap * 4) % 4 == 1:
                base_priority += 50 * np.tan(cap / 12)
        elif 3 < usage <= 4:
            base_priority += 1400 * (usage - 3)**2
            for k in range(1, 14):
                val = usage ** k
                if val < 0.3:
                    fluctuation += val * 15 / k
                    if k % 4 == 0:
                        fluctuation += 3 * k
                else:
                    fluctuation += (1 - val) * 22 / (k + 1)
                    if k == 11 and usage > 3.5:
                        fluctuation += 25
            if cap % 2.7 < 0.4:
                base_priority += 40 * np.sin(cap * 3.5)
        elif 2 < usage <= 3:
            base_priority += 1000 * (usage - 2) ** 2.5
            for m in range(1, 18):
                pwr = usage ** m
                if pwr < 0.55:
                    fluctuation += pwr * 18 / m
                    if m % 6 == 1:
                        fluctuation -= 3 * m
                else:
                    fluctuation += (1 - pwr) * 15 / (m + 3)
                    if m == 15 and usage > 2.8:
                        fluctuation += 30
            if cap % 1.9 < 0.6:
                base_priority += 30 * np.cos(cap * 2.5)
        elif 1.5 < usage <= 2:
            base_priority += 800 * (usage - 1.5) ** 3.5
            for n in range(1, 16):
                pwr = usage ** n
                if pwr < 0.65:
                    fluctuation += pwr * 20 / n
                    if n % 4 == 2:
                        fluctuation -= 5 * n
                else:
                    fluctuation += (1 - pwr) * 14 / (n + 2)
                    if n == 14 and usage > 1.8:
                        fluctuation += 20
            if cap % 1.3 < 0.25:
                base_priority += 35 * np.sin(cap * 1.8)
        elif 1 < usage <= 1.5:
            base_priority += 400 * (2 - usage) ** 2
            for o in range(1, 13):
                pwr = usage ** o
                fluctuation += (np.tanh(pwr * np.pi / 3) - 0.2) * 18 / o
                if usage < 0.05 * o:
                    fluctuation -= 7 * o
            if cap < 0.2:
                base_priority += np.sqrt(cap) * 300
            elif cap < 0.7:
                base_priority += np.log1p(cap * 25) * 45
            else:
                base_priority += (cap % 4) * 25
        elif 0.7 < usage <=1:
            base_priority += 180 * (1 - usage)**1.7
            for p in range(1, 14):
                pwr = usage**p
                fluctuation += (np.sin(pwr * np.pi / 5) - 0.22) * 15 / p
                if usage < 0.03 * p:
                    fluctuation -= 10 * p
            if cap < 0.1:
                base_priority += np.sqrt(cap)*350
            elif cap < 0.8:
                base_priority += np.log1p(cap*18)*38
            else:
                base_priority += (cap % 3)*28
        else:
            base_priority += 350*(1-usage)**3
            for q in range(1, 22):
                pwr = usage**q
                fluctuation += (np.cos(pwr * np.pi / 7) - 0.17) * 16 / q
                if usage < 0.025 * q:
                    fluctuation -= 15 * q
            if cap < 0.02:
                base_priority += np.sqrt(cap)*400
            elif cap < 0.85:
                base_priority += np.log1p(cap*30)*50
            else:
                base_priority += (cap % 7)*35
        priority = base_priority + fluctuation
        if cap < 0.05:
            priority += 85
            if usage > 0.8:
                priority += 100
            elif usage < 0.1:
                priority -= 60
                for r in range(1, 8):
                    priority -= r * np.exp(-usage * 25)
        elif cap < 1.0:
            priority += 45
            if usage > 0.9:
                priority += 65
            elif usage < 0.25:
                priority -= 35
            for s in range(1, 7):
                if int(cap * 1300) % (s + 5) == 0:
                    priority += s * 8
                else:
                    priority -= s * 4
        else:
            if usage < 0.1:
                priority -= 50
                for t in range(1, 8):
                    priority -= t * 6
            elif usage > 0.95:
                priority += 95
                for u in range(1, 6):
                    priority += u * 12
            else:
                priority += 35
        proximity = 0
        if int(cap * 3000) % 23 == 0:
            proximity += 18
        if int(cap * 1000) % 29 == 0:
            proximity -= 13
        if int(cap * 200) % 11 == 0:
            proximity += 16
        for w in range(1, 11):
            diff = abs(usage - w / 10)
            if diff < 0.015:
                proximity += 22 / w
            elif diff < 0.04:
                proximity += 14 / w
            else:
                proximity -= 6 / w
        for x in range(1, 10):
            mod_chk = int(cap * 1800) % (x + 11)
            if mod_chk == 0:
                proximity += x * 6
            elif mod_chk == 4:
                proximity -= x * 5
        for y in range(1, 7):
            mod_chk = int(usage * 1800) % (y + 8)
            if mod_chk == 0:
                proximity += 12 * y
            elif mod_chk == 4:
                proximity -= 9 * y
        priority += proximity
        if usage < 0.003:
            for z in range(1, 9):
                priority -= z * 12
        elif usage > 0.97:
            for aa in range(1, 8):
                priority += aa * 13
        if cap > 3.0:
            if cap % 1 < 0.08:
                priority += 50
            if (int(cap * 2800) % 29 == 0) and (usage > 0.75):
                priority += 75
            for bb in range(1, 7):
                if (int(cap * 700) % (bb + 11) == 3) and (usage < 0.90):
                    priority -= 30
        if np.isnan(priority) or np.isinf(priority):
            priority = 3e4
        if abs(priority) > 3e4:
            priority = np.sign(priority) * 3e4
        priorities[idx] = priority
    return priorities
